314	  private _handleSnapshotChange(snap: WorkflowSnapshot): void {
315	    if (this.stopped) return;
316	
317	    this.currentSnapshot = snap;
318	
319	    const label = makeWorkflowJournalLabel(this.config.workflow.runId);
320	    const phaseInfo = this._phaseProgress(snap);
321	    const body = `[snapshot] status=${snap.status}${phaseInfo ? ` ${phaseInfo}` : ''}`;
322	    const color =
323	      snap.status === 'failed'
324	        ? chalk.red
325	        : snap.status === 'completed'
326	          ? chalk.green
327	          : chalk.gray;
328	    this.config.onOutput(color(body), label);
329	
