      sessionUuid: 'uuid',
      sessionDir,
      onNewWorkflow: () => {},
      outputHandler: handler,
    });
    await detector.start();
    expect(() => detector.stop()).not.toThrow();
    expect(() => detector.stop()).not.toThrow();
  });

  test('onNewWorkflow rejection → runId rolled back, retried, eventually succeeds', async () => {
    const handler = createCapturingHandler();
