private watchParentForSubagentsDir(): void {
  if (!this.isWatching) return;
  if (this.parentWatcher) return;

  const parentDir = join(this.subagentsDir, '..');
  try {
    this.parentWatcher = watch(parentDir, () => {
      this.tryWatchSubagentsDir();
    });
